import os
from base64 import b64encode
import requests
from PIL import Image
from io import BytesIO
from selenium import webdriver
import boto3

def get_screenshot(url):
    options = webdriver.ChromeOptions()
    options.add_argument('--headless')
    driver = webdriver.Chrome(options=options)
    driver.get(url)
    screenshot = BytesIO()
    driver.save_screenshot(screenshot)
    image = Image.open(screenshot)
    thumbnail = image.resize((200, 200))
    thumbnail.save(screenshot, 'JPEG')
    screenshot = screenshot.getvalue()
    return screenshot

def save_to_s3(bucket_name, key, data):
    s3 = boto3.client('s3')
    s3.put_object(Bucket=bucket_name, Key=key, Body=data)

def main():
    url = "https://www.google.com"  # Replace with the URL from your user
    screenshot_data = get_screenshot(url)
    encoded_screenshot = b64encode(screenshot_data).decode('utf-8')
    save_to_s3("mybucket", f"screenshot_{url}.jpeg", encoded_screenshot)
    driver.quit()

if __name__ == "__main__":
    main()